import React, { useState, useEffect, useCallback } from 'react';
import { devicesApi } from './lib/api';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Terminal from './components/Terminal';
import Backups from './components/Backups';
import AuditLogs from './components/AuditLogs';
import Settings from './components/Settings';

function mapDeviceFromApi(apiDevice) {
  return {
    id: apiDevice.id,
    name: apiDevice.hostname || '',
    ip: apiDevice.ip_address || '',
    port: apiDevice.port || 22,
    vendor: apiDevice.vendor || '',
    model: apiDevice.model || '',
    os_version: apiDevice.os_version || '',
    serial_number: apiDevice.serial_number || '',
    device_type: apiDevice.is_bras ? 'bras' : 'router',
    status: 'online',
    ssh_user: apiDevice.username || '',
    ssh_password: apiDevice.password || '',
    snmp_community: apiDevice.snmp_community || '',
    snmp_port: apiDevice.snmp_port || 161,
    snmp_version: apiDevice.snmp_version || 'v2c',
    librenms_id: apiDevice.librenms_id,
    web_url: apiDevice.web_url || '',
    protocol: apiDevice.protocol || 'SSH',
    backup_enabled: apiDevice.backup_enabled,
    backup_frequency: apiDevice.backup_frequency || 'daily',
    backup_time: apiDevice.backup_time || '01:00',
    pppoe_count: 0,
  };
}

function mapDeviceToApi(device) {
  const apiData = {};
  if (device.id) apiData.id = device.id;
  if (device.name) apiData.hostname = device.name;
  if (device.ip) apiData.ip_address = device.ip;
  if (device.port) apiData.port = device.port;
  if (device.vendor !== undefined) apiData.vendor = device.vendor;
  if (device.model !== undefined) apiData.model = device.model;
  if (device.ssh_user !== undefined) apiData.username = device.ssh_user;
  if (device.ssh_password !== undefined) apiData.password = device.ssh_password;
  if (device.snmp_community !== undefined) apiData.snmp_community = device.snmp_community;
  if (device.snmp_port) apiData.snmp_port = device.snmp_port;
  if (device.snmp_version) apiData.snmp_version = device.snmp_version;
  if (device.librenms_id) apiData.librenms_id = device.librenms_id;
  if (device.web_url !== undefined) apiData.web_url = device.web_url;
  if (device.device_type) apiData.is_bras = device.device_type === 'bras';
  if (device.backup_enabled !== undefined) apiData.backup_enabled = device.backup_enabled;
  if (device.backup_frequency) apiData.backup_frequency = device.backup_frequency;
  if (device.backup_time) apiData.backup_time = device.backup_time;
  return apiData;
}

function App() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [devices, setDevices] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [notification, setNotification] = useState(null);

  const showNotification = (message, type = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const [devicesData, statsData] = await Promise.all([
        devicesApi.list(),
        devicesApi.dashboard(),
      ]);

      const mappedDevices = (devicesData || []).map(mapDeviceFromApi);

      if (statsData?.pppoe_details) {
        mappedDevices.forEach(device => {
          const pppoe = statsData.pppoe_details.find(
            p => p.name === device.name || p.ip === device.ip
          );
          if (pppoe) device.pppoe_count = pppoe.count;
        });
      }

      setDevices(mappedDevices);
      setStats(statsData);
    } catch (error) {
      console.error('Error fetching data:', error);
      showNotification('Erro ao carregar dados', 'error');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 60000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const handleAddDevice = async (device) => {
    try {
      const apiData = mapDeviceToApi(device);
      await devicesApi.save(apiData);
      showNotification('Dispositivo adicionado com sucesso!');
      fetchData();
    } catch (error) {
      console.error('Error adding device:', error);
      showNotification('Erro ao adicionar dispositivo', 'error');
      throw error;
    }
  };

  const handleUpdateDevice = async (device) => {
    try {
      const apiData = mapDeviceToApi(device);
      await devicesApi.save(apiData);
      showNotification('Dispositivo atualizado com sucesso!');
      fetchData();
    } catch (error) {
      console.error('Error updating device:', error);
      showNotification('Erro ao atualizar dispositivo', 'error');
      throw error;
    }
  };

  const handleDeleteDevice = async (id) => {
    try {
      await devicesApi.delete(id);
      showNotification('Dispositivo removido com sucesso!');
      fetchData();
    } catch (error) {
      console.error('Error deleting device:', error);
      showNotification('Erro ao remover dispositivo', 'error');
      throw error;
    }
  };

  const handleOpenTerminal = (device) => {
    setActiveTab('terminal');
  };

  const handleRunBackup = async (deviceId) => {
    try {
      await devicesApi.runBackup(deviceId);
      showNotification('Backup iniciado!');
    } catch (error) {
      showNotification('Erro ao iniciar backup', 'error');
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard stats={stats} devices={devices} loading={loading} onRefresh={fetchData} />;
      case 'inventory':
        return (
          <Inventory
            devices={devices}
            loading={loading}
            onRefresh={fetchData}
            onAddDevice={handleAddDevice}
            onUpdateDevice={handleUpdateDevice}
            onDeleteDevice={handleDeleteDevice}
            onOpenTerminal={handleOpenTerminal}
            onRunBackup={handleRunBackup}
          />
        );
      case 'terminal':
        return <Terminal devices={devices} />;
      case 'backups':
        return <Backups devices={devices} loading={loading} onRefresh={fetchData} onRunBackup={handleRunBackup} />;
      case 'audit':
        return <AuditLogs devices={devices} loading={loading} onRefresh={fetchData} />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard stats={stats} devices={devices} loading={loading} onRefresh={fetchData} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background">
      {notification && (
        <div className={'fixed top-4 right-4 z-50 px-4 py-3 rounded-lg shadow-lg ' + (notification.type === 'error' ? 'bg-red-500/90' : 'bg-green-500/90') + ' text-white'}>
          {notification.message}
        </div>
      )}

      <Sidebar activeTab={activeTab} onTabChange={setActiveTab} serverHealth={stats?.server_health} />
      <main className="flex-1 p-6 lg:ml-0 overflow-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

export default App;
